// Helper: 20 interview pairs → 20 activities + 20 quiz (aligned: same concept per pair)
function buildFromPairs(pairs) {
  const activities = pairs.map((p) => ({
    type: 'multiple-choice',
    instruction: p.instruction || ('Interview: ' + p.question),
    options: p.options.map((o) => ({ id: o.id, text: o.text })),
    correctAnswer: p.correctAnswer,
    explanation: p.explanation,
  }));
  const quizQuestions = pairs.map((p) => ({
    question: p.question,
    options: p.options.map((o) => ({ id: o.id, text: o.text })),
    correctOptionId: p.correctOptionId || p.correctAnswer,
    explanation: p.explanation,
  }));
  return { activities, quizQuestions };
}

