// Shorthand for interview pairs (question, instruction, array of option texts, correct letter, explanation)
function pair(q, inst, opts, ans, exp) {
  const options = opts.map((t, i) => ({ id: String.fromCharCode(97 + i), text: t }));
  return { question: q, instruction: inst || q, options, correctAnswer: ans, correctOptionId: ans, explanation: exp };
}
